#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 13
#define QUEUESIZE 1000000

// Structure to represent a state
typedef struct {
    int config[MAX];
    int moves;
} State;

// Function to apply a move to a state
void applyMove(State *state, int hexagon, int direction) {
    // Apply the move
    if (direction == 0) {
        // Counter-clockwise
        int temp = state->config[hexagon * 3];
        state->config[hexagon * 3] = state->config[hexagon * 3 + 1];
        state->config[hexagon * 3 + 1] = state->config[hexagon * 3 + 2];
        state->config[hexagon * 3 + 2] = temp;
    } else {
        // Clockwise
        int temp = state->config[hexagon * 3 + 2];
        state->config[hexagon * 3 + 2] = state->config[hexagon * 3 + 1];
        state->config[hexagon * 3 + 1] = state->config[hexagon * 3];
        state->config[hexagon * 3] = temp;
    }
}

// Function to check if a state is the solution
int isSolution(State *state) {
    // Check if all shared vertexes are black
    return state->config[3] == 1 && state->config[6] == 1 && state->config[9] == 1 && state->config[12] == 1;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        char input[MAX + 1];
        scanf("%s", input);
        State initialState;
        for (int i = 0; i < MAX; i++) {
            initialState.config[i] = input[i] - '0';
        }
        initialState.moves = 0;
        State queue[QUEUESIZE];
        int front = 0, rear = 0;
        queue[rear++] = initialState;
        while (front < rear) {
            State currentState = queue[front++];
            if (isSolution(&currentState)) {
                printf("%d\n", currentState.moves);
                // Print the moves
                for (int i = 0; i < currentState.moves; i++) {
                    printf("%d %d\n", i / 2, i % 2);
                }
                break;
            }
            // Apply all possible moves
            for (int hexagon = 0; hexagon < 3; hexagon++) {
                for (int direction = 0; direction < 2; direction++) {
                    State newState = currentState;
                    applyMove(&newState, hexagon, direction);
                    newState.moves++;
                    queue[rear++] = newState;
                }
            }
        }
        if (front == rear) {
            printf("No solution\n");
        }
    }
    return 0;
}

