import java.util.LinkedList;
import java.util.Queue;
import java.util.Scanner;
public class Main {
    static final int MAX = 13;
    static class State {
        int[] config;
        int moves;
        State(int[] config, int moves) {
            this.config = config;
            this.moves = moves;
        }
    }

    public static void applyMove(State state, int hexagon, int direction) {
        // Apply the move
        if (direction == 0) {
            // Counter-clockwise
            int temp = state.config[hexagon * 3];
            state.config[hexagon * 3] = state.config[hexagon * 3 + 1];
            state.config[hexagon * 3 + 1] = state.config[hexagon * 3 + 2];
            state.config[hexagon * 3 + 2] = temp;
        } else {
            // Clockwise
            int temp = state.config[hexagon * 3 + 2];
            state.config[hexagon * 3 + 2] = state.config[hexagon * 3 + 1];
            state.config[hexagon * 3 + 1] = state.config[hexagon * 3];
            state.config[hexagon * 3] = temp;
        }
    }

    public static boolean isSolution(State state) {
        // Check if all shared vertexes are black
        return state.config[3] == 1 && state.config[6] == 1 && state.config[9] == 1 && state.config[12] == 1;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            String input = scanner.next();
            int[] config = new int[MAX];
            for (int i = 0; i < MAX; i++) {
                config[i] = input.charAt(i) - '0';
            }
            State initialState = new State(config, 0);
            Queue<State> queue = new LinkedList<>();
            queue.add(initialState);
            boolean found = false;
            while (!queue.isEmpty()) {
                State currentState = queue.poll();
                if (isSolution(currentState)) {
                    System.out.println(currentState.moves);
                    // Print the moves
                    for (int i = 0; i < currentState.moves; i++) {
                        System.out.println(i / 2 + " " + i % 2);
                    }
                    found = true;
                    break;
                }
                // Apply all possible moves
                for (int hexagon = 0; hexagon < 3; hexagon++) {
                    for (int direction = 0; direction < 2; direction++) {
                        int[] newConfig = currentState.config.clone();
                        State newState = new State(newConfig, currentState.moves + 1);
                        applyMove(newState, hexagon, direction);
                        queue.add(newState);
                    }
                }
            }
            if (!found) {
                System.out.println("No solution");
            }
        }
    }
}

