const MAX = 13;

class State {
    constructor(config, moves) {
        this.config = config;
        this.moves = moves;
    }
}

function applyMove(state, hexagon, direction) {
    // Apply the move
    if (direction === 0) {
        // Counter-clockwise
        const temp = state.config[hexagon * 3];
        state.config[hexagon * 3] = state.config[hexagon * 3 + 1];
        state.config[hexagon * 3 + 1] = state.config[hexagon * 3 + 2];
        state.config[hexagon * 3 + 2] = temp;
    } else {
        // Clockwise
        const temp = state.config[hexagon * 3 + 2];
        state.config[hexagon * 3 + 2] = state.config[hexagon * 3 + 1];
        state.config[hexagon * 3 + 1] = state.config[hexagon * 3];
        state.config[hexagon * 3] = temp;
    }
}

function isSolution(state) {
    // Check if all shared vertexes are black
    return state.config[3] === 1 && state.config[6] === 1 && state.config[9] === 1 && state.config[12] === 1;
}

const T = readInt();
for (let t = 0; t < T; t++) {
    const inputStr = readString();
    const config = inputStr.split('').map(x => parseInt(x));
    const initialState = new State(config, 0);
    const queue = [initialState];
    let found = false;
    while (queue.length > 0) {
        const currentState = queue.shift();
        if (isSolution(currentState)) {
